module RefModule(CLK, EN, TE, ENCLK);input CLK, EN, TE;
  output ENCLK;

  reg ENCLK_reg;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (EN) begin
      ENCLK_reg <= TE;
    end
  end

  assign ENCLK = EN ? ENCLK_reg : 1'b0;

endmodule
